_carousel_html = f"""
<style>
#caro{{
    position:relative;
    border-radius:14px;
    overflow:hidden;
    height:260px;
    border:1px solid rgba(118,120,237,0.35);
    cursor:pointer;
    user-select:none;
    margin:10px 0 20px 0;
}}
#ci{{
    display:flex;
    height:100%;
    width:300%;
    transition:transform 0.55s cubic-bezier(.4,0,.2,1);
}}
.cs{{
    flex:0 0 33.333%;
    height:100%;
    position:relative;
    overflow:hidden;
}}
.cs img{{
    width:100%;
    height:100%;
    object-fit:cover;
    display:block;
    pointer-events:none;
}}
.cap{{
    position:absolute;
    bottom:0;
    left:0;
    right:0;
    background:linear-gradient(transparent,rgba(26,21,69,0.95));
    color:#fff;
    font-family:'DM Sans',sans-serif;
    font-size:14px;
    font-weight:500;
    padding:32px 24px 14px;
    text-align:center;
    letter-spacing:0.3px;
}}
#dots{{
    position:absolute;
    bottom:12px;
    left:50%;
    transform:translateX(-50%);
    display:flex;
    gap:10px;
    z-index:20;
}}
.dot{{
    width:8px;
    height:8px;
    border-radius:50%;
    background:rgba(255,255,255,0.4);
    transition:background .3s;
    cursor:pointer;
}}
.dot.on{{
    background:#F7B801;
}}
</style>

<div id='caro'>
    <div id='ci'>
        <div class='cs'>
            <img src='data:image/jpeg;base64,{pic1_base64}' alt='Framework Map Matrix'>
            <div class='cap'>📊 Profile Framework Map Matrix — Country-level education indicator correlations</div>
        </div>
        <div class='cs'>
            <img src='data:image/jpeg;base64,{pic2_base64}' alt='Distribution Density Plot'>
            <div class='cap'>📈 Distribution Architecture Density Plot — Global schooling distribution patterns</div>
        </div>
        <div class='cs'>
            <img src='data:image/jpeg;base64,{pic3_base64}' alt='Predictive Driver Modeling'>
            <div class='cap'>🤖 Predictive Driver Modeling & Projections — Machine learning insights</div>
        </div>
    </div>
    <div id='dots'>
        <div class='dot on' id='d0'></div>
        <div class='dot' id='d1'></div>
        <div class='dot' id='d2'></div>
    </div>
</div>

<script>
var c=0,T=3,tmr;
function go(n){{
    c=(n+T)%T;
    document.getElementById('ci').style.transform='translateX(-'+(c*33.333)+'%)';
    for(var i=0;i<T;i++){{
        var d=document.getElementById('d'+i);
        if(d) d.className='dot'+(i===c?' on':'');
    }}
}}
function nxt(){{ go(c+1); }}
tmr=setInterval(nxt,4000);
var el=document.getElementById('caro');
el.addEventListener('mouseenter',function(){{ clearInterval(tmr); }});
el.addEventListener('mouseleave',function(){{ tmr=setInterval(nxt,4000); }});
el.addEventListener('mousemove',function(e){{
    var r=el.getBoundingClientRect();
    var z=Math.min(Math.floor((e.clientX-r.left)/(r.width/T)),T-1);
    if(z!==c) go(z);
}});
for(var i=0;i<T;i++){{ (function(idx){{
    var d=document.getElementById('d'+idx);
    if(d) d.onclick=function(){{ go(idx); }};
}})(i); }}
</script>
"""

