def delta_str(curr, prev, fmt=".2f"):
    if prev == 0: return ""
    d = curr - prev
    color = C3 if d >= 0 else C5
    arrow = "▲" if d >= 0 else "▼"
    return f"<span style='color:{color};font-size:12px;'>{arrow} {abs(d):{fmt}}</span>"

