    yearly_stats = df.groupby("Year")["avg_years_schooling"].agg(["mean","min","max"]).reset_index()
    fig_trend = go.Figure()
    fig_trend.add_trace(go.Scatter(x=yearly_stats["Year"],y=yearly_stats["max"],fill=None,mode="lines",line=dict(width=0),showlegend=False,name="Max"))
    fig_trend.add_trace(go.Scatter(x=yearly_stats["Year"],y=yearly_stats["min"],fill="tonexty",mode="lines",line=dict(width=0),fillcolor="rgba(118,120,237,0.15)",showlegend=False,name="Min"))
    fig_trend.add_trace(go.Scatter(x=yearly_stats["Year"],y=yearly_stats["mean"],mode="lines+markers",name="Global Avg",line=dict(color=C3,width=2.5),marker=dict(size=5,color=C3)))
    fig_trend.add_vline(x=selected_year,line_dash="dash",line_color=C5,line_width=1.5,annotation_text=str(selected_year),annotation_font_color=C5)
    fig_trend.update_layout(**chart_layout(height=300))
    st.plotly_chart(fig_trend,use_container_width=True)
    st.markdown(f"<div class='insight-box' style='margin-top:0;'>📌 Global average schooling rose from <strong>{yearly_stats["mean"].iloc[0]:.2f} years</strong> in 2000 to <strong>{yearly_stats["mean"].iloc[-1]:.2f} years</strong> in 2023 — a steady upward trend across all regions, though significant gaps between rich and poor countries persist.</div>", unsafe_allow_html=True)
